// ============================================
// ELAB Compile Service — Arduino Code Compiler
// Riceve { code, board } e compila via arduino-cli
// Fallback n8n per quando il compile-server standalone è offline
// © Andrea Marro — 19/02/2026
// ============================================

const { execFileSync } = require('child_process');
const fs = require('fs');
const path = require('path');
const os = require('os');
const crypto = require('crypto');

const body = $input.first().json.body;
const code = body.code;
const board = body.board || 'arduino:avr:nano:cpu=atmega328old';

if (!code || typeof code !== 'string' || code.trim().length === 0) {
  return [{ json: { success: false, hex: null, errors: 'Codice mancante o vuoto', output: null } }];
}

const ALLOWED = new Set(['arduino:avr:nano:cpu=atmega328old', 'arduino:avr:uno']);
if (!ALLOWED.has(board)) {
  return [{ json: { success: false, hex: null, errors: 'Board non supportata: ' + board, output: null } }];
}

const tmpId = crypto.randomBytes(8).toString('hex');
const tmpDir = path.join(os.tmpdir(), 'elab-compile-' + tmpId);
const sketchDir = path.join(tmpDir, 'sketch');

try {
  fs.mkdirSync(sketchDir, { recursive: true });
  fs.writeFileSync(path.join(sketchDir, 'sketch.ino'), code, 'utf8');

  const buildDir = path.join(tmpDir, 'build');
  fs.mkdirSync(buildDir, { recursive: true });

  let stdout = '';
  try {
    stdout = execFileSync('arduino-cli', [
      'compile', '--fqbn', board, '--output-dir', buildDir, '--warnings', 'default', sketchDir
    ], { timeout: 60000, encoding: 'utf8', maxBuffer: 5 * 1024 * 1024 });
  } catch (compileError) {
    const stderr = compileError.stderr || '';
    const errOut = compileError.stdout || '';
    const clean = (stderr + '\n' + errOut)
      .replace(new RegExp(sketchDir.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'g'), 'sketch')
      .replace(new RegExp(tmpDir.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'g'), '.')
      .trim();
    return [{ json: { success: false, hex: null, errors: clean || 'Errore di compilazione', output: errOut.trim() || null } }];
  }

  let hex = null;
  const hexFile = path.join(buildDir, 'sketch.ino.hex');
  const altHex = path.join(buildDir, 'sketch.ino.with_bootloader.hex');
  if (fs.existsSync(hexFile)) hex = fs.readFileSync(hexFile, 'utf8');
  else if (fs.existsSync(altHex)) hex = fs.readFileSync(altHex, 'utf8');

  const cleanOut = stdout
    .replace(new RegExp(sketchDir.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'g'), 'sketch')
    .replace(new RegExp(tmpDir.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'g'), '.')
    .trim();

  return [{ json: { success: true, hex: hex, errors: null, output: cleanOut || 'Compilazione completata' } }];

} catch (error) {
  return [{ json: { success: false, hex: null, errors: 'Errore interno: ' + error.message, output: null } }];
} finally {
  try { fs.rmSync(tmpDir, { recursive: true, force: true }); } catch {}
}
